-- ENGINEER_WRITTEN 2024년 제2회 기출 복원 — 100문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 주의: 최초 배포 시 입력 JSON 의 examYear 가 2025 로 잘못 들어갔으나
-- 실제 회차는 2024년 정기 기사 2회. 운영 DB 의 stale (2025, 2) row 는
-- 후속 V57 마이그레이션이 정리한다.
--
-- 재실행 안전성 — 동일 조합(exam_type + PAST_EXAM + 연도/회차) 정리 후 재삽입
DELETE FROM mock_exam
  WHERE exam_type = 'ENGINEER_WRITTEN'
    AND kind = 'PAST_EXAM'
    AND exam_year = 2024
    AND exam_round = 2;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'ENGINEER_WRITTEN');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('정보처리기사 필기 2024년 2회 복원', 'ENGINEER_WRITTEN', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2024, 2, '2024-05-15', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '나선형(Spiral) 모델에 대한 설명으로 옳지 않은 것은 무엇인가?\n\n① 복잡한 대형 프로젝트에서 위험 분석에 기여한다.\n② 개발 중 발생할 수 있는 위험을 최소화하는 것이 주 목적이며, 유지보수 단계가 필요 없다.\n③ 나선을 돌듯 반복하며 점진적으로 완성도를 높인다.\n④ 프로토타입을 개발 과정에 반영할 수 있다.', 'MCQ', 2, '정답: 2. 나선형 모델은 위험 분석을 중시하지만 유지보수 단계가 필요 없다는 설명은 틀리다.\n\n**오답 풀이**\n- 1번: 대형 프로젝트의 위험 분석에 적합하므로 맞는 설명이다.\n- 2번: 위험 최소화는 맞지만 유지보수가 필요 없다는 부분이 틀렸다.\n- 3번: 반복적·점진적으로 개발하는 나선형 모델의 특징이다.\n- 4번: 프로토타입을 활용하여 요구사항을 확인할 수 있다.\n\n**보충 개념**\n나선형 모델은 계획 수립, 위험 분석, 개발 및 검증, 고객 평가를 반복하며 위험을 관리하는 개발 모델이다.',
   '나선형 모델', 2, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '결합도의 품질이 높은 순에서 낮은 순으로 올바르게 나열한 것은?\n\n① 내용 결합도 → 공통 결합도 → 외부 결합도 → 제어 결합도 → 스탬프 결합도 → 자료 결합도\n② 자료 결합도 → 스탬프 결합도 → 제어 결합도 → 외부 결합도 → 공통 결합도 → 내용 결합도\n③ 제어 결합도 → 스탬프 결합도 → 자료 결합도 → 공통 결합도 → 내용 결합도\n④ 외부 결합도 → 공통 결합도 → 내용 결합도 → 자료 결합도 → 스탬프 결합도 → 제어 결합도', 'MCQ', 2, '정답: 2. 결합도는 낮을수록 품질이 높으며, 자료 결합도가 가장 낮고 내용 결합도가 가장 높다.\n\n**오답 풀이**\n- 1번: 내용 결합도는 가장 나쁜 결합도이므로 가장 앞에 오면 안 된다.\n- 2번: 자료 → 스탬프 → 제어 → 외부 → 공통 → 내용 순서가 품질 높은 순서이다.\n- 3번: 제어 결합도가 자료 결합도보다 앞에 있어 순서가 틀렸다.\n- 4번: 내용 결합도와 자료 결합도의 위치가 부적절하다.\n\n**보충 개념**\n좋은 설계는 결합도를 낮추고 응집도를 높이는 방향을 지향한다.',
   '결합도', 2, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'HIPO(Hierarchy Input Process Output) 차트에 대한 설명으로 옳지 않은 것은?\n\n① 기능과 데이터의 관계를 계층 구조로 표현하여 한눈에 이해하기 쉽게 한다.\n② 시스템의 기능을 여러 개의 고유 모듈로 분할하여 계층적으로 나타낸다.\n③ 기능과 자료의 의존성을 동시에 표현할 수 있으며 상호 교류도 나타낸다.\n④ 가시적, 총체적, 세부적 도표로 나누어진다.', 'MCQ', 3, '정답: 3. HIPO는 기능을 계층적으로 표현하고 입력·처리·출력을 나타내는 도구이지, 기능과 자료의 상호 교류를 표현하는 도구는 아니다.\n\n**오답 풀이**\n- 1번: HIPO는 기능과 입출력 관계를 계층적으로 표현한다.\n- 2번: 시스템 기능을 모듈 단위로 분할해 계층적으로 나타낸다.\n- 3번: 상호 교류나 자료 의존성 표현은 HIPO의 핵심 설명과 거리가 있다.\n- 4번: HIPO는 가시적 도표, 총체적 도표, 세부적 도표로 구분된다.\n\n**보충 개념**\nHIPO는 하향식 소프트웨어 개발 문서화에 활용된다.',
   'HIPO', 2, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'FTR(Formal Technical Review)에 해당하지 않는 것은?\n\n① 검토할 제품에 대한 체크리스트를 개발한다.\n② 문제 영역을 명확히 표현하고 의제를 제한한다.\n③ 해결책이나 개선책에 대해 논의한다.\n④ 사전 준비를 강화하고 사전에 작성한 메모를 공유한다.', 'MCQ', 3, '정답: 3. FTR은 산출물의 오류 발견에 집중하며 해결책이나 개선책 논의는 제한한다.\n\n**오답 풀이**\n- 1번: 체크리스트는 검토 품질을 높이는 데 사용된다.\n- 2번: 의제를 제한하고 문제 영역을 명확히 하는 것은 FTR 원칙이다.\n- 3번: 해결책 논의 중심의 회의는 FTR 원칙과 거리가 멀다.\n- 4번: 사전 준비와 메모 공유는 FTR에 적절하다.\n\n**보충 개념**\nFTR은 사람에 대한 평가가 아니라 제품 자체의 결함을 찾는 공식 검토 기법이다.',
   'FTR', 2, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '서버가 통신용 프로그램을 생성하여 포트를 할당하고, 클라이언트 요청 시 연결하여 통신하는 네트워크 기술은?\n\n① DB Link\n② API\n③ Socket\n④ Web Service', 'MCQ', 3, '정답: 3. 소켓은 서버와 클라이언트가 포트를 통해 연결하여 통신하는 네트워크 인터페이스이다.\n\n**오답 풀이**\n- 1번: DB Link는 데이터베이스 간 연결 기술이다.\n- 2번: API는 응용 프로그램 간 기능 호출 인터페이스이다.\n- 3번: Socket은 네트워크 통신을 위한 끝점이다.\n- 4번: Web Service는 네트워크 상에서 API처럼 기능을 제공하는 방식이다.\n\n**보충 개념**\n소켓 통신은 IP 주소와 포트 번호를 기반으로 서버와 클라이언트가 데이터를 주고받는다.',
   'Socket', 1, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '형상 관리(Configuration Management)에 대한 설명으로 옳지 않은 것은?\n\n① 소프트웨어 개발 과정에서 발생하는 변경 사항을 체계적으로 관리한다.\n② 소프트웨어 무결성과 일관성을 유지하고 개발 효율성을 높인다.\n③ 프로젝트 개발의 전 과정에서 발생하는 모든 산출물에 적용된다.\n④ 형상 식별, 형상 통제, 형상 감사, 형상 기록의 4가지 절차로 구성된다.', 'MCQ', 4, '정답: 4. 형상 관리는 일반적으로 형상 식별, 형상 통제, 형상 감사, 형상 상태 보고로 구성된다.\n\n**오답 풀이**\n- 1번: 변경 사항을 체계적으로 관리하는 것이 형상 관리이다.\n- 2번: 형상 관리는 무결성과 일관성 유지에 기여한다.\n- 3번: 소스코드, 문서, 산출물 등 개발 전 과정의 산출물에 적용된다.\n- 4번: 형상 기록이 아니라 형상 상태 보고가 대표 구성 요소이다.\n\n**보충 개념**\n형상 관리는 변경 이력을 추적하고 승인된 변경만 반영되도록 통제한다.',
   '형상 관리', 2, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 비용 산정 모델에 해당하지 않는 것은?\n\n① COCOMO 모델\n② 기능 점수(Function Point) 모델\n③ Putnam 모델\n④ SWOT 분석 모델', 'MCQ', 4, '정답: 4. SWOT 분석은 강점, 약점, 기회, 위협을 분석하는 경영 분석 기법이며 비용 산정 모델이 아니다.\n\n**오답 풀이**\n- 1번: COCOMO는 소프트웨어 비용 산정 모델이다.\n- 2번: 기능 점수 모델은 기능 규모를 기준으로 비용을 산정한다.\n- 3번: Putnam 모델은 소프트웨어 생명주기와 비용 예측에 사용된다.\n- 4번: SWOT 분석은 비용 산정 모델이 아니다.\n\n**보충 개념**\n대표적인 비용 산정 기법에는 LOC, 기능 점수, COCOMO, Putnam 등이 있다.',
   '비용 산정', 1, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '애자일(Agile) 모델에 대한 설명으로 옳지 않은 것은?\n\n① 고객과의 소통과 협업을 중요하게 생각한다.\n② 절차, 문서, 계획보다는 변화에 대한 대응에 가치를 둔다.\n③ 짧은 개발 주기를 반복하면서 고객 피드백을 수용한다.\n④ 소프트웨어 개발 초기부터 모든 기능을 완벽하게 계획하고 문서화하는 것을 목표로 한다.', 'MCQ', 4, '정답: 4. 애자일은 초기 완전 계획과 문서화보다 변화 대응과 고객 피드백을 중시한다.\n\n**오답 풀이**\n- 1번: 애자일은 고객과의 소통을 중시한다.\n- 2번: 애자일은 변화 대응에 높은 가치를 둔다.\n- 3번: 짧은 반복 주기로 피드백을 반영한다.\n- 4번: 초기부터 모든 것을 완벽히 문서화하는 것은 애자일과 거리가 멀다.\n\n**보충 개념**\n애자일은 작게 만들고 빠르게 검증하며 반복적으로 개선하는 개발 방식이다.',
   '애자일', 2, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '스크럼 모델의 스프린트 주기로 옳은 것은?\n\n① 1~2주\n② 2~4주\n③ 6~8주\n④ 8~12주', 'MCQ', 2, '정답: 2. 스크럼의 스프린트는 일반적으로 2~4주 정도의 짧은 반복 주기로 수행된다.\n\n**오답 풀이**\n- 1번: 1~2주는 가능한 짧은 반복일 수 있으나 일반적인 기준 답으로는 부족하다.\n- 2번: 2~4주가 일반적인 스프린트 주기이다.\n- 3번: 6~8주는 스프린트 주기로는 길다.\n- 4번: 8~12주는 스크럼의 짧은 반복 주기와 맞지 않는다.\n\n**보충 개념**\n스프린트는 일정한 기간 동안 제품 증분을 개발하는 스크럼의 반복 단위이다.',
   '스크럼', 1, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 공학의 이점과 가장 거리가 먼 것은?\n\n① 개발에 필요한 비용과 기간 예측에 도움을 준다.\n② 소프트웨어에 대한 체계적 비용 절감에 도움을 준다.\n③ 소프트웨어 품질과 생산성 향상에 기여한다.\n④ 반드시 비용을 증가시킨다.', 'MCQ', 4, '정답: 4. 소프트웨어 공학은 비용 증가가 아니라 체계적 개발을 통해 품질과 생산성을 높이고 비용을 절감하는 데 목적이 있다.\n\n**오답 풀이**\n- 1번: 비용과 기간 예측에 도움을 준다.\n- 2번: 체계적 접근은 비용 절감에 기여할 수 있다.\n- 3번: 품질과 생산성 향상은 소프트웨어 공학의 이점이다.\n- 4번: 반드시 비용을 증가시킨다는 설명은 부적절하다.\n\n**보충 개념**\n소프트웨어 공학은 개발, 운영, 유지보수에 공학적 원리를 적용하는 분야이다.',
   '소프트웨어 공학', 1, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'XP(eXtreme Programming) 모델의 가치에 해당하지 않는 것은?\n\n① 의사소통\n② 단순성\n③ 존중\n④ 복잡성', 'MCQ', 4, '정답: 4. XP의 핵심 가치는 의사소통, 단순성, 피드백, 용기, 존중이며 복잡성은 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 의사소통은 XP의 핵심 가치이다.\n- 2번: 단순성은 XP의 핵심 가치이다.\n- 3번: 존중은 XP의 핵심 가치이다.\n- 4번: 복잡성은 XP의 가치가 아니다.\n\n**보충 개념**\nXP는 짧은 반복과 적극적인 고객 피드백, 테스트 중심 개발을 강조한다.',
   'XP', 1, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'CASE 도구의 특징에 대한 설명으로 옳지 않은 것은?\n\n① 개발 프로세스 전 과정에서 자동화를 지원한다.\n② 품질 향상과 생산성 향상에 기여한다.\n③ 유지보수 비용은 비교적 작고 개발 비용 및 기간은 절감된다.\n④ 명령어 및 문법 숙지가 필수이며 CASE 도구 간 호환성이 높다.', 'MCQ', 4, '정답: 4. CASE 도구는 그래픽 기반 지원과 자동화를 제공하지만 도구 간 호환성이 항상 높다고 보기 어렵다.\n\n**오답 풀이**\n- 1번: CASE는 개발 과정 자동화를 지원한다.\n- 2번: 품질과 생산성 향상에 기여한다.\n- 3번: 문서화와 표준화를 통해 유지보수 비용 절감에 도움을 준다.\n- 4번: 명령어 숙지가 필수이고 호환성이 높다는 설명은 부적절하다.\n\n**보충 개념**\nCASE는 소프트웨어 개발 생명주기 전반을 지원하는 자동화 도구이다.',
   'CASE', 2, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '요구공학 프로세스를 올바른 순서로 나열한 것은?\n\n① 요구사항 도출 → 요구사항 분석 → 요구사항 명세 → 요구사항 확인 및 검증\n② 요구사항 분석 → 요구사항 도출 → 요구사항 명세 → 요구사항 확인 및 검증\n③ 요구사항 명세 → 요구사항 분석 → 요구사항 도출 → 요구사항 확인 및 검증\n④ 요구사항 도출 → 요구사항 명세 → 요구사항 분석 → 요구사항 확인 및 검증', 'MCQ', 1, '정답: 1. 요구공학은 일반적으로 요구사항 도출, 분석, 명세, 확인 및 검증 순서로 진행된다.\n\n**오답 풀이**\n- 1번: 올바른 순서이다.\n- 2번: 도출보다 분석이 먼저 올 수 없다.\n- 3번: 명세는 분석 이후에 작성된다.\n- 4번: 분석과 명세의 순서가 바뀌었다.\n\n**보충 개념**\n요구공학은 사용자의 요구를 체계적으로 수집하고 명확히 정의하기 위한 활동이다.',
   '요구공학', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '유스케이스 다이어그램에서 사용자의 목적 달성을 위해 서비스를 제공하는 외부 시스템(조직, 기관)을 의미하는 것은?\n\n① 주 액터\n② 부 액터\n③ 시스템 행위\n④ 유스케이스', 'MCQ', 2, '정답: 2. 부 액터는 주 액터의 목적 달성을 지원하는 외부 시스템이나 조직을 의미한다.\n\n**오답 풀이**\n- 1번: 주 액터는 시스템을 사용해 목적을 달성하려는 주요 사용자이다.\n- 2번: 부 액터는 외부 시스템이나 지원 주체이다.\n- 3번: 시스템 행위는 액터의 종류가 아니다.\n- 4번: 유스케이스는 사용자가 얻는 기능이나 서비스이다.\n\n**보충 개념**\n유스케이스 다이어그램은 액터와 유스케이스 사이의 상호작용을 표현한다.',
   '유스케이스 다이어그램', 2, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '자료 흐름도(DFD)의 구성 요소에 대한 설명으로 옳지 않은 것은?\n\n① 프로세스는 자료 처리 과정을 나타내며 타원으로 표기한다.\n② 자료 흐름은 자료 흐름 방향을 나타내며 화살표로 표기한다.\n③ 자료 저장소는 데이터가 저장되는 곳을 나타내며 사각형으로 표기한다.\n④ 단말은 데이터 입출력 주체를 나타내며 직사각형으로 표기한다.', 'MCQ', 3, '정답: 3. 자료 저장소는 일반적으로 평행선 또는 열린 사각형 형태로 표현하며 단순 사각형으로만 설명하는 것은 부적절하다.\n\n**오답 풀이**\n- 1번: 프로세스는 자료 처리 과정을 나타낸다.\n- 2번: 자료 흐름은 화살표로 방향을 표시한다.\n- 3번: 자료 저장소의 표기 설명이 부정확하다.\n- 4번: 단말은 외부 개체로 직사각형으로 표현한다.\n\n**보충 개념**\nDFD의 구성 요소는 프로세스, 자료 흐름, 자료 저장소, 단말이다.',
   'DFD', 2, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '비정형/정형 명세 기법에 대한 특징으로 가장 거리가 먼 것은?\n\n① 정형 명세 기법은 수학적 표현을 사용하여 요구사항을 정확하게 표현한다.\n② 정형 명세 기법은 오류와 모호성을 쉽게 파악할 수 있다.\n③ 비정형 명세 기법은 자연어 기반으로 요구사항을 친숙하게 표현한다.\n④ 비정형 명세 기법은 완전한 검증이 가능하며 다양한 표현으로 오해 가능성이 없다.', 'MCQ', 4, '정답: 4. 비정형 명세 기법은 자연어를 사용하기 때문에 오해나 모호성이 발생할 수 있다.\n\n**오답 풀이**\n- 1번: 정형 명세는 수학적 표기법을 사용한다.\n- 2번: 정형 명세는 모호성 제거에 유리하다.\n- 3번: 비정형 명세는 자연어 기반이므로 이해가 쉽다.\n- 4번: 비정형 명세가 완전 검증 가능하다는 설명은 틀렸다.\n\n**보충 개념**\n정형 명세는 정확하지만 작성이 어렵고, 비정형 명세는 이해가 쉽지만 모호성이 생길 수 있다.',
   '요구사항 명세', 2, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '코드 인스펙션(Code Inspection)에 대한 설명으로 옳지 않은 것은?\n\n① 프로그램을 실행하지 않고 소스코드를 분석한다.\n② 결함 분석에 검사 목록을 사용한다.\n③ 프로그램을 실행하여 검사하는 동적 테스트이다.\n④ 초기 개발 단계에 적용 가능하다.', 'MCQ', 3, '정답: 3. 코드 인스펙션은 프로그램을 실행하지 않고 검사하는 정적 분석 기법이다.\n\n**오답 풀이**\n- 1번: 실행 없이 소스코드를 검토한다.\n- 2번: 체크리스트를 사용할 수 있다.\n- 3번: 실행 기반 동적 테스트가 아니다.\n- 4번: 개발 초기에도 적용 가능하다.\n\n**보충 개념**\n정적 분석은 실행 전 코드 결함, 표준 위반, 품질 문제를 찾는 방법이다.',
   '코드 인스펙션', 2, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'UML에서 흐름도처럼 시스템이나 객체의 프로세스 및 로직의 처리 흐름을 순서에 따라 표현하는 다이어그램은?\n\n① 유스케이스 다이어그램\n② 클래스 다이어그램\n③ 활동 다이어그램\n④ 상태 다이어그램', 'MCQ', 3, '정답: 3. 활동 다이어그램은 처리 흐름, 제어 흐름, 업무 흐름을 순서대로 표현한다.\n\n**오답 풀이**\n- 1번: 유스케이스 다이어그램은 기능 요구와 액터 관계를 표현한다.\n- 2번: 클래스 다이어그램은 정적 구조를 표현한다.\n- 3번: 활동 다이어그램은 처리 흐름을 표현한다.\n- 4번: 상태 다이어그램은 객체의 상태 변화를 표현한다.\n\n**보충 개념**\n활동 다이어그램은 업무 프로세스나 알고리즘 흐름을 모델링할 때 사용된다.',
   '활동 다이어그램', 2, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'UI(User Interface) 설계 원칙에 대한 설명으로 옳지 않은 것은?\n\n① 직관성은 별다른 이해 노력 없이 즉시 사용 가능해야 함을 의미한다.\n② 유효성은 사용자의 목적을 정확하게 달성할 수 있어야 함을 의미한다.\n③ 학습성은 누구나 쉽게 배우고 익혀 재사용할 수 있도록 설계해야 함을 의미한다.\n④ 유연성은 사용자의 요구사항을 수용하고 오류를 최소화하는 정도를 의미한다.', 'MCQ', 3, '정답: 3. 학습성은 쉽게 배우고 익힐 수 있는 정도이며, 재사용성 중심의 설명은 적절하지 않다.\n\n**오답 풀이**\n- 1번: 직관성의 설명이다.\n- 2번: 유효성의 설명이다.\n- 3번: 학습성 설명에 재사용 의미가 섞여 부적절하다.\n- 4번: 유연성은 요구 수용과 오류 최소화와 관련된다.\n\n**보충 개념**\nUI 설계 원칙에는 직관성, 유효성, 학습성, 유연성이 있다.',
   'UI 설계', 2, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'UX(User Experience)에 대한 설명으로 옳지 않은 것은?\n\n① 사용자가 시스템을 이용하며 느끼는 총체적 경험을 뜻한다.\n② 단순 기능과 절차가 아니라 시스템과 상호작용 과정에서 얻는 만족감까지 포함한다.\n③ UI가 사용자 편의성을 중시한다면 UX는 이를 통해 느끼는 만족감을 중시한다.\n④ UX의 특징으로는 주관성, 정량성, 기능성이 있다.', 'MCQ', 4, '정답: 4. UX의 특징으로는 주관성, 정황성, 총체성 등이 있으며 정량성·기능성만으로 설명하기 어렵다.\n\n**오답 풀이**\n- 1번: UX는 사용자의 전체 경험이다.\n- 2번: 사용 과정의 만족감까지 포함한다.\n- 3번: UI와 UX의 차이를 설명한 것이다.\n- 4번: UX의 대표 특징 설명으로 부적절하다.\n\n**보충 개념**\nUX는 제품이나 서비스를 사용하는 과정에서 사용자가 느끼는 인식과 반응을 포괄한다.',
   'UX', 2, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '테스트 오류의 유형에 해당하지 않는 것은?\n\n① 참(True) 오류\n② 샘플링(Sampling) 오류\n③ 휴리스틱(Heuristic) 오류\n④ 로직(Logic) 오류', 'MCQ', 2, '정답: 2. 샘플링 오류는 일반적인 소프트웨어 테스트 오류 유형으로 보기 어렵다.\n\n**오답 풀이**\n- 1번: 참 오류는 테스트 결과 판단과 관련될 수 있다.\n- 2번: 샘플링 오류는 대표 테스트 오류 유형이 아니다.\n- 3번: 휴리스틱 오류는 경험 기반 판단 오류와 관련될 수 있다.\n- 4번: 로직 오류는 프로그램 논리 오류이다.\n\n**보충 개념**\n테스트 오류 유형은 시험 맥락에서 제시된 분류 기준에 따라 구분해야 한다.',
   '테스트 오류', 2, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '블랙박스 테스트 기법에 대한 설명으로 옳지 않은 것은?\n\n① 입력 조건의 경계에서 오류 발생 확률이 높다는 점을 이용한다.\n② 입력 데이터 간 관계와 출력에 미치는 영향을 분석한다.\n③ 과거 경험이나 확인자의 감각에 의존하여 테스트 케이스를 설계한다.\n④ 프로그램 내부 로직, 경로 구조, 루프 등을 중심으로 테스트를 진행한다.', 'MCQ', 4, '정답: 4. 프로그램 내부 로직과 경로 구조를 중심으로 하는 것은 화이트박스 테스트이다.\n\n**오답 풀이**\n- 1번: 경계값 분석은 블랙박스 테스트 기법이다.\n- 2번: 원인-효과 그래프는 블랙박스 테스트 기법이다.\n- 3번: 오류 예측은 경험 기반 블랙박스 테스트 기법이다.\n- 4번: 내부 구조 중심 테스트는 화이트박스 테스트이다.\n\n**보충 개념**\n블랙박스 테스트는 내부 구조를 보지 않고 입력과 출력의 관계를 검증한다.',
   '블랙박스 테스트', 2, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래 트리를 중위 순회한 경로로 옳은 것은?\n\n**<그림>**\n<svg xmlns="http://www.w3.org/2000/svg" width="420" height="210" viewBox="0 0 420 210" role="img" aria-label="이진 트리"><style>.node{fill:#fff;stroke:#333;stroke-width:2}.edge{stroke:#333;stroke-width:2}.txt{font-size:16px;font-family:Arial,sans-serif;text-anchor:middle;dominant-baseline:middle}</style><line x1="210" y1="35" x2="130" y2="85" class="edge"/><line x1="210" y1="35" x2="290" y2="85" class="edge"/><line x1="130" y1="85" x2="70" y2="145" class="edge"/><line x1="290" y1="85" x2="240" y2="145" class="edge"/><line x1="290" y1="85" x2="340" y2="145" class="edge"/><line x1="340" y1="145" x2="380" y2="185" class="edge"/><circle cx="210" cy="35" r="22" class="node"/><text x="210" y="35" class="txt">C</text><circle cx="130" cy="85" r="22" class="node"/><text x="130" y="85" class="txt">B</text><circle cx="290" cy="85" r="22" class="node"/><text x="290" y="85" class="txt">E</text><circle cx="70" cy="145" r="22" class="node"/><text x="70" y="145" class="txt">A</text><circle cx="240" cy="145" r="22" class="node"/><text x="240" y="145" class="txt">D</text><circle cx="340" cy="145" r="22" class="node"/><text x="340" y="145" class="txt">F</text><circle cx="380" cy="185" r="22" class="node"/><text x="380" y="185" class="txt">G</text></svg>\n\n① A-B-C-D-E-F-G\n② C-A-B-D-E-F-G\n③ C-B-A-E-D-F-G\n④ A-B-D-G-F-E-C', 'MCQ', 1, '정답: 1. 중위 순회는 왼쪽 서브트리 → 루트 → 오른쪽 서브트리 순서로 방문한다.\n\n**오답 풀이**\n- 1번: A-B-C-D-E-F-G로 중위 순회 결과와 일치한다.\n- 2번: 루트를 먼저 방문하므로 중위 순회가 아니다.\n- 3번: B와 A의 방문 순서가 틀렸다.\n- 4번: 오른쪽 서브트리 순서가 중위 순회와 맞지 않는다.\n\n**보충 개념**\n이진 트리 순회에서 중위 순회는 Left → Root → Right 순서이다.',
   '트리 순회', 3, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'DRM(Digital Rights Management)에 대한 설명과 가장 거리가 먼 것은?\n\n① 완료된 제품 소프트웨어를 고객에게 전달하기 위한 형태로 묶는 방법이다.\n② 개발 과정에서 발생하는 산출물의 변경과 흐름을 체계적으로 관리한다.\n③ 디지털 콘텐츠의 불법 복제와 유통을 방지하고 이용 권한을 제한하는 기술과 절차이다.\n④ 디지털 콘텐츠를 보호하기 위해 기존 운영체제에 보안 기능을 추가한 운영체제이다.', 'MCQ', 3, '정답: 3. DRM은 디지털 콘텐츠의 무단 복제와 사용을 통제하기 위한 기술이다.\n\n**오답 풀이**\n- 1번: 제품 전달 형태는 패키징 설명에 가깝다.\n- 2번: 산출물 변경 관리는 형상 관리 설명이다.\n- 3번: DRM의 핵심 설명이다.\n- 4번: 보안 운영체제에 대한 설명에 가깝다.\n\n**보충 개념**\nDRM은 암호화, 키 관리, 라이선스 관리, 정책 제어 등을 포함한다.',
   'DRM', 2, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '각 부분에서 가장 최적의 해를 선택하여 결과적으로 최적해를 도출하려는 알고리즘 기법은?\n\n① 동적 계획법\n② 탐욕적 알고리즘\n③ 재귀적 알고리즘\n④ 퇴각 검색법', 'MCQ', 2, '정답: 2. 탐욕적 알고리즘은 각 단계에서 가장 좋아 보이는 선택을 반복하여 해를 구한다.\n\n**오답 풀이**\n- 1번: 동적 계획법은 부분 문제의 해를 저장해 활용한다.\n- 2번: 탐욕적 알고리즘은 매 단계의 최선 선택을 사용한다.\n- 3번: 재귀적 알고리즘은 자기 자신을 호출하는 방식이다.\n- 4번: 퇴각 검색법은 가능한 해를 탐색하다가 조건에 맞지 않으면 되돌아간다.\n\n**보충 개념**\n탐욕적 알고리즘은 항상 최적해를 보장하지는 않지만 특정 조건에서는 효율적으로 최적해를 구할 수 있다.',
   '탐욕 알고리즘', 2, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '제품 소프트웨어 설치 매뉴얼에 포함되지 않는 것은?\n\n① 제품 소프트웨어 개요\n② 설치 관련 파일\n③ 소프트웨어 수정을 위한 소스코드\n④ 설치 이상 시 메시지 설명', 'MCQ', 3, '정답: 3. 설치 매뉴얼은 설치 절차와 환경, 오류 대응을 설명하며 소스코드 수정용 자료는 포함 대상이 아니다.\n\n**오답 풀이**\n- 1번: 제품 개요는 설치 매뉴얼에 포함될 수 있다.\n- 2번: 설치 관련 파일 설명은 포함될 수 있다.\n- 3번: 소스코드는 설치 매뉴얼의 일반 구성 요소가 아니다.\n- 4번: 설치 오류 메시지 설명은 포함될 수 있다.\n\n**보충 개념**\n설치 매뉴얼은 사용자가 제품을 정상적으로 설치하고 실행할 수 있도록 안내하는 문서이다.',
   '설치 매뉴얼', 1, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '프로그램 내부 로직과 경로를 추적하며 논리 구조를 고려해 테스트하는 것은?\n\n① 블랙박스 테스트\n② 화이트박스 테스트\n③ 인수 테스트\n④ 단위 테스트', 'MCQ', 2, '정답: 2. 화이트박스 테스트는 프로그램 내부 구조, 경로, 조건, 반복 등을 분석하여 테스트한다.\n\n**오답 풀이**\n- 1번: 블랙박스 테스트는 내부 구조를 보지 않는다.\n- 2번: 화이트박스 테스트는 내부 로직을 기반으로 한다.\n- 3번: 인수 테스트는 사용자 요구사항 충족 여부를 확인한다.\n- 4번: 단위 테스트는 모듈 단위 기능을 확인한다.\n\n**보충 개념**\n화이트박스 테스트에는 기초 경로 테스트, 조건 검사, 루프 검사 등이 있다.',
   '화이트박스 테스트', 1, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'V-모델에서 가장 마지막에 진행되는 테스트 기법으로, 사용자가 직접 요구사항 충족 여부를 확인하는 테스트는?\n\n① 단위 테스트\n② 통합 테스트\n③ 시스템 테스트\n④ 인수 테스트', 'MCQ', 4, '정답: 4. 인수 테스트는 사용자의 요구사항을 만족하는지 최종적으로 확인하는 테스트이다.\n\n**오답 풀이**\n- 1번: 단위 테스트는 가장 작은 모듈을 검증한다.\n- 2번: 통합 테스트는 모듈 간 연동을 검증한다.\n- 3번: 시스템 테스트는 전체 시스템이 명세대로 동작하는지 확인한다.\n- 4번: 인수 테스트는 최종 사용자 관점에서 수행된다.\n\n**보충 개념**\nV-모델의 테스트 순서는 단위 → 통합 → 시스템 → 인수 테스트이다.',
   'V-모델', 1, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '수열 [39, 45, 26, 35, 54]를 삽입 정렬할 경우 1회전 후 결과는?\n\n① [26, 39, 45, 35, 54]\n② [39, 26, 45, 35, 54]\n③ [39, 26, 45, 35, 54]\n④ [26, 35, 39, 45, 54]', 'MCQ', 1, '정답: 1. 첫 번째 회전에서 26이 앞의 39, 45와 비교되어 제자리인 맨 앞으로 삽입된다.\n\n**오답 풀이**\n- 1번: 26이 앞쪽으로 이동한 1회전 결과이다.\n- 2번: 26이 39 뒤에 남아 있어 삽입이 끝나지 않은 상태이다.\n- 3번: 2번과 같은 잘못된 결과이다.\n- 4번: 전체 정렬이 완료된 결과에 가깝다.\n\n**보충 개념**\n삽입 정렬은 선택한 원소를 앞쪽의 정렬된 부분에 알맞은 위치로 삽입한다.',
   '삽입 정렬', 2, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '선형 자료 구조의 종류가 아닌 것은?\n\n① 스택(Stack)\n② 큐(Queue)\n③ 데크(Deque)\n④ 트리(Tree)', 'MCQ', 4, '정답: 4. 트리는 계층 구조를 갖는 비선형 자료 구조이다.\n\n**오답 풀이**\n- 1번: 스택은 선형 자료 구조이다.\n- 2번: 큐는 선형 자료 구조이다.\n- 3번: 데크는 양쪽 삽입·삭제가 가능한 선형 자료 구조이다.\n- 4번: 트리는 비선형 자료 구조이다.\n\n**보충 개념**\n선형 자료 구조는 데이터가 일렬로 구성되고, 비선형 자료 구조는 계층 또는 그래프 형태를 가진다.',
   '자료 구조', 1, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '인터페이스 구현 검증을 지원하는 도구가 아닌 것은?\n\n① JUnit\n② STAF\n③ Selenium\n④ JTAF', 'MCQ', 4, '정답: 4. JTAF는 대표적인 인터페이스 구현 검증 도구로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: JUnit은 xUnit 계열 테스트 도구이다.\n- 2번: STAF는 테스트 자동화 프레임워크이다.\n- 3번: Selenium은 웹 테스트 자동화 도구로 활용된다.\n- 4번: JTAF는 대표 검증 도구 목록에 해당하지 않는다.\n\n**보충 개념**\n인터페이스 구현 검증 도구에는 xUnit, STAF, FitNesse, NTAF, Selenium 등이 있다.',
   '인터페이스 검증', 2, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '하나의 리스트를 기준값(pivot)을 기준으로 나누고 정렬하는 정렬 알고리즘은?\n\n① 삽입 정렬\n② 버블 정렬\n③ 퀵 정렬\n④ 선택 정렬', 'MCQ', 3, '정답: 3. 퀵 정렬은 피벗을 기준으로 작은 값과 큰 값을 분할한 뒤 재귀적으로 정렬한다.\n\n**오답 풀이**\n- 1번: 삽입 정렬은 앞쪽 정렬 영역에 원소를 삽입한다.\n- 2번: 버블 정렬은 인접 원소를 비교·교환한다.\n- 3번: 퀵 정렬은 피벗 기준 분할을 사용한다.\n- 4번: 선택 정렬은 최소 또는 최대 원소를 선택해 위치를 바꾼다.\n\n**보충 개념**\n퀵 정렬은 평균 시간 복잡도가 O(n log n)이다.',
   '퀵 정렬', 2, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '중위식 `A*B+C-D`를 후위식으로 올바르게 변환한 것은?\n\n① AB*C+D-\n② AB*C+D\n③ ABC*+D-\n④ AB*+CD-', 'MCQ', 3, '정답: 3. 곱셈을 먼저 처리하고, 덧셈과 뺄셈을 왼쪽에서 오른쪽으로 변환하면 `AB*C+D-`가 된다.\n\n**오답 풀이**\n- 1번: 연산자 배치가 일부 틀렸다.\n- 2번: 마지막 뺄셈 연산자가 누락되었다.\n- 3번: 올바른 후위 표기식이다.\n- 4번: 덧셈과 뺄셈의 피연산자 순서가 부적절하다.\n\n**보충 개념**\n후위 표기식은 연산자를 피연산자 뒤에 쓰며, 연산자 우선순위를 반영해야 한다.',
   '후위 표기식', 3, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 품질 특성 중 기능성(Functionality)의 하위 분류에 해당하지 않는 것은?\n\n① 상호운용성\n② 보안성\n③ 준수성\n④ 진단성', 'MCQ', 4, '정답: 4. 진단성은 기능성의 대표 하위 특성이 아니다.\n\n**오답 풀이**\n- 1번: 상호운용성은 기능성 하위 특성이다.\n- 2번: 보안성은 기능성 하위 특성으로 분류된다.\n- 3번: 준수성은 기능성 하위 특성이다.\n- 4번: 진단성은 기능성 하위 분류와 거리가 멀다.\n\n**보충 개념**\nISO/IEC 9126의 기능성에는 적합성, 정확성, 상호운용성, 보안성, 준수성 등이 포함된다.',
   '소프트웨어 품질', 2, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '형상 관리 도구에서 개발자가 수정한 소스코드를 저장소에 업로드하는 기능은?\n\n① check-out\n② check-in\n③ commit\n④ update', 'MCQ', 2, '정답: 2. check-in은 수정한 파일을 저장소에 반영하는 기능이다.\n\n**오답 풀이**\n- 1번: check-out은 저장소에서 파일을 내려받아 작업하는 기능이다.\n- 2번: check-in은 변경 내용을 저장소에 반영한다.\n- 3번: commit은 버전 관리 시스템에서 변경 이력을 기록하는 용어로 쓰이지만 제시 문맥의 정답은 check-in이다.\n- 4번: update는 저장소의 최신 내용을 작업 공간에 반영하는 기능이다.\n\n**보충 개념**\n형상 관리 도구는 소스코드 버전과 변경 이력을 관리한다.',
   '형상 관리', 2, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 제품 개발 과정에 대한 테스트와 결과에 대한 테스트를 각각 올바르게 짝지은 것은?\n\n**<보기>**\nㄱ: 소프트웨어 제품의 개발 과정에 대한 테스트\nㄴ: 소프트웨어 제품의 개발 결과에 대한 테스트\n\n① ㄱ: Validation, ㄴ: Verification\n② ㄱ: Verification, ㄴ: Validation\n③ ㄱ: Debugging, ㄴ: Test\n④ ㄱ: Test, ㄴ: Debugging', 'MCQ', 2, '정답: 2. Verification은 개발 과정이 올바른지 확인하고, Validation은 결과물이 사용자 요구를 만족하는지 확인한다.\n\n**오답 풀이**\n- 1번: Verification과 Validation의 위치가 반대이다.\n- 2번: 올바른 조합이다.\n- 3번: Debugging은 결함 수정 활동이다.\n- 4번: Test와 Debugging은 검증·확인 개념 구분에 맞지 않는다.\n\n**보충 개념**\nVerification은 “제품을 올바르게 만들고 있는가”, Validation은 “올바른 제품을 만들었는가”를 확인한다.',
   '검증과 확인', 2, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '제품 소프트웨어의 특정 특성을 파악하기 위한 목적 기반 테스트 유형에 해당하지 않는 것은?\n\n① 회복 테스트\n② 강도 테스트\n③ 성능 테스트\n④ 블랙박스 테스트', 'MCQ', 4, '정답: 4. 블랙박스 테스트는 내부 구조를 보지 않는 테스트 설계 관점이며, 특정 품질 특성 목적 테스트 유형과는 구분된다.\n\n**오답 풀이**\n- 1번: 회복 테스트는 장애 후 복구 능력을 확인한다.\n- 2번: 강도 테스트는 한계 상황에서의 동작을 확인한다.\n- 3번: 성능 테스트는 처리량, 응답시간 등을 확인한다.\n- 4번: 블랙박스 테스트는 테스트 설계 기법이다.\n\n**보충 개념**\n목적 기반 테스트에는 회복, 안전, 강도, 성능, 구조, 회귀, 병행 테스트 등이 있다.',
   '테스트 유형', 2, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '비결정성 알고리즘의 해결 전략을 구현하기 위해 중앙 데이터 저장소와 지식 소스가 문제 해결에 협력하는 패턴은?\n\n① MVC 패턴\n② 미디에이터 패턴\n③ 블랙보드 패턴\n④ 클라이언트-서버 패턴', 'MCQ', 3, '정답: 3. 블랙보드 패턴은 중앙 저장소와 여러 지식 소스가 협력해 해를 찾는 구조이다.\n\n**오답 풀이**\n- 1번: MVC는 모델, 뷰, 컨트롤러로 역할을 분리한다.\n- 2번: 미디에이터 패턴은 객체 간 상호작용을 중재한다.\n- 3번: 블랙보드 패턴은 비결정성 문제 해결에 적합하다.\n- 4번: 클라이언트-서버는 요청자와 제공자를 분리한다.\n\n**보충 개념**\n블랙보드 패턴은 음성 인식, 영상 인식, 신호 해석 같은 문제 해결에 활용된다.',
   '블랙보드 패턴', 2, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'XML을 대체하는 독립적인 개방형 표준 형식으로, 자바스크립트를 기반으로 속성-값 쌍으로 데이터를 표현하는 것은?\n\n① XML\n② JSON\n③ YAML\n④ HTML', 'MCQ', 2, '정답: 2. JSON은 JavaScript 객체 표기법을 기반으로 속성-값 쌍 형태의 데이터를 표현한다.\n\n**오답 풀이**\n- 1번: XML은 마크업 기반 데이터 표현 형식이다.\n- 2번: JSON은 경량 데이터 교환 형식이다.\n- 3번: YAML은 사람이 읽기 쉬운 데이터 직렬화 형식이다.\n- 4번: HTML은 웹 문서 구조를 표현하는 마크업 언어이다.\n\n**보충 개념**\nJSON은 웹 API 응답 형식으로 널리 사용된다.',
   'JSON', 1, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'NS(Nassi-Shneiderman) 차트에 대한 설명으로 옳은 것은?\n\n① 처리 프로세스를 도형으로 표현한 차트이다.\n② 화살표와 GOTO문을 사용한다.\n③ 순차, 선택, 반복 제어구조를 명확히 표현한다.\n④ 임의 제어 이동이 많다.', 'MCQ', 3, '정답: 3. NS 차트는 순차, 선택, 반복 구조를 블록으로 표현하는 구조적 설계 도구이다.\n\n**오답 풀이**\n- 1번: 일반적인 순서도 설명에 가깝다.\n- 2번: NS 차트는 GOTO와 화살표를 사용하지 않는다.\n- 3번: 순차·선택·반복 구조 표현이 핵심이다.\n- 4번: 임의 제어 이동을 지양한다.\n\n**보충 개념**\nNS 차트는 구조적 프로그래밍의 논리 흐름을 명확하게 표현한다.',
   'NS 차트', 2, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '원천 데이터에서 데이터를 추출하고 분석 가능한 형태로 변환한 후 최종 시스템에 적재하는 데이터 처리 과정은?\n\n① CRM\n② ERP\n③ ETL\n④ BI', 'MCQ', 3, '정답: 3. ETL은 Extract, Transform, Load의 약자로 데이터를 추출·변환·적재하는 과정이다.\n\n**오답 풀이**\n- 1번: CRM은 고객 관계 관리이다.\n- 2번: ERP는 전사적 자원 관리이다.\n- 3번: ETL은 데이터 추출, 변환, 적재 과정이다.\n- 4번: BI는 기업 데이터 분석과 의사결정 지원을 의미한다.\n\n**보충 개념**\nETL은 데이터 웨어하우스나 분석 시스템 구축에 자주 사용된다.',
   'ETL', 1, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'VIEW에 대한 설명으로 옳지 않은 것은?\n\n① 논리적 데이터 구조로 실제 데이터는 저장하지 않는다.\n② 뷰의 정의는 시스템 카탈로그에 저장된다.\n③ 뷰를 통해 다른 뷰를 정의할 수 없으며 반드시 기본 테이블만 참조해야 한다.\n④ 데이터 독립성과 보안성을 유지할 수 있다.', 'MCQ', 3, '정답: 3. 뷰를 기반으로 다른 뷰를 정의할 수 있으므로 해당 설명은 틀리다.\n\n**오답 풀이**\n- 1번: 일반적인 뷰는 실제 데이터를 저장하지 않는 가상 테이블이다.\n- 2번: 뷰의 정의는 시스템 카탈로그에 저장된다.\n- 3번: 뷰를 기반으로 또 다른 뷰를 만들 수 있다.\n- 4번: 뷰는 보안성과 논리적 독립성 향상에 활용된다.\n\n**보충 개념**\n뷰는 복잡한 질의를 단순화하고 사용자별 접근 범위를 제한할 수 있다.',
   '뷰', 2, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '데이터 정의어(DDL)에 해당하지 않는 명령은?\n\n① CREATE\n② ALTER\n③ DROP\n④ SELECT', 'MCQ', 4, '정답: 4. SELECT는 데이터를 조회하는 DML 명령어이다.\n\n**오답 풀이**\n- 1번: CREATE는 DDL이다.\n- 2번: ALTER는 DDL이다.\n- 3번: DROP은 DDL이다.\n- 4번: SELECT는 DML이다.\n\n**보충 개념**\nDDL에는 CREATE, ALTER, DROP, TRUNCATE 등이 있다.',
   'DDL', 1, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '릴레이션에서 차수(Degree)에 대한 설명으로 옳은 것은?\n\n① 전체 튜플의 개수이다.\n② 전체 속성의 개수이다.\n③ 도메인의 개수이다.\n④ Null 값의 개수이다.', 'MCQ', 2, '정답: 2. 차수는 릴레이션을 구성하는 속성의 개수이다.\n\n**오답 풀이**\n- 1번: 튜플의 개수는 카디널리티이다.\n- 2번: 속성의 개수가 차수이다.\n- 3번: 도메인은 속성값의 범위이다.\n- 4번: Null 개수와는 관계없다.\n\n**보충 개념**\n릴레이션에서 행은 튜플, 열은 속성이다.',
   '릴레이션', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '관계 해석(Relational Calculus)에 대한 설명으로 옳지 않은 것은?\n\n① 원하는 정보가 무엇인지만 정의하는 비절차적 언어이다.\n② SQL은 관계 해석과 관계 대수를 기반으로 한다.\n③ 관계 대수와 관계 해석은 관계 DB 처리 능력을 표현한다.\n④ 관계 해석 연산자는 OR, AND, NOT 외에 PROJECT, SELECT 등이 있다.', 'MCQ', 4, '정답: 4. PROJECT와 SELECT는 관계 대수의 순수 관계 연산자이며 관계 해석 연산자가 아니다.\n\n**오답 풀이**\n- 1번: 관계 해석은 비절차적 언어이다.\n- 2번: SQL은 관계 대수와 관계 해석의 영향을 받았다.\n- 3번: 둘 다 관계형 데이터베이스 질의 표현 능력을 가진다.\n- 4번: PROJECT와 SELECT는 관계 대수 연산이다.\n\n**보충 개념**\n관계 해석은 원하는 결과의 조건을 논리식으로 표현한다.',
   '관계 해석', 2, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '회원 테이블의 부서번호 필드가 부서 테이블을 참조하는 경우 해당 키는?\n\n① 외래키\n② 후보키\n③ 슈퍼키\n④ 기본키', 'MCQ', 1, '정답: 1. 다른 릴레이션의 기본키를 참조하는 속성은 외래키이다.\n\n**오답 풀이**\n- 1번: 외래키는 다른 테이블의 기본키를 참조한다.\n- 2번: 후보키는 유일성과 최소성을 만족하는 키이다.\n- 3번: 슈퍼키는 유일성을 만족하는 속성 집합이다.\n- 4번: 기본키는 튜플을 대표 식별하는 키이다.\n\n**보충 개념**\n외래키는 릴레이션 간 참조 무결성을 유지하는 데 사용된다.',
   '외래키', 1, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '1NF를 만족하고 모든 비기본 속성이 기본키에 완전 함수 종속하며, 이행 함수 종속을 제거한 정규형은?\n\n① 제1정규형(1NF)\n② 제3정규형(3NF)\n③ BCNF\n④ 제4정규형(4NF)', 'MCQ', 2, '정답: 2. 제3정규형은 제2정규형을 만족하고 이행 함수 종속을 제거한 정규형이다.\n\n**오답 풀이**\n- 1번: 1NF는 속성값의 원자성을 만족한다.\n- 2번: 3NF는 이행 함수 종속을 제거한다.\n- 3번: BCNF는 모든 결정자가 후보키인 더 강한 정규형이다.\n- 4번: 4NF는 다치 종속 제거와 관련된다.\n\n**보충 개념**\n정규화는 데이터 중복과 이상 현상을 줄이기 위한 과정이다.',
   '정규화', 2, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '권한을 부여받은 사용자가 다른 사용자에게 권한을 다시 부여할 수 있고, 취소 시 연쇄 취소가 가능한 옵션은?\n\n① ON UPDATE CASCADE\n② WITH GRANT OPTION\n③ ON DELETE RESTRICT\n④ WITH ADMIN OPTION', 'MCQ', 2, '정답: 2. WITH GRANT OPTION은 부여받은 권한을 다른 사용자에게 다시 부여할 수 있게 한다.\n\n**오답 풀이**\n- 1번: ON UPDATE CASCADE는 참조 무결성 옵션이다.\n- 2번: WITH GRANT OPTION은 권한 재부여를 허용한다.\n- 3번: ON DELETE RESTRICT는 삭제 제한 옵션이다.\n- 4번: WITH ADMIN OPTION은 역할 권한 부여와 관련된다.\n\n**보충 개념**\nWITH GRANT OPTION으로 부여된 권한은 회수 시 연쇄적으로 취소될 수 있다.',
   'GRANT', 2, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '''영업'' 부서의 평균 급여보다 더 많은 급여를 받는 직원의 EmpID, Name, Dept, Salary를 조회하는 SQL로 옳은 것은?\n\n① SELECT EmpID, Name, Dept, Salary FROM Employees WHERE Dept=''영업'' AND Salary > (SELECT AVG(Salary) FROM Employees WHERE Dept=''영업'');\n② SELECT EmpID, Name, Dept, Salary FROM Employees WHERE Salary > (SELECT AVG(Salary) FROM Employees WHERE Dept=''영업'');\n③ SELECT EmpID, Name, Dept, Salary FROM Employees WHERE Salary = (SELECT AVG(Salary) FROM Employees WHERE Dept=''영업'');\n④ SELECT EmpID, Name, Dept, Salary FROM Employees WHERE Dept=''영업'' OR Salary > (SELECT AVG(Salary) FROM Employees WHERE Dept=''영업'');', 'MCQ', 2, '정답: 2. 모든 직원 중 ''영업'' 부서 평균 급여보다 큰 직원을 조회해야 하므로 부서 조건은 서브쿼리에만 있어야 한다.\n\n**오답 풀이**\n- 1번: 영업 부서 직원으로만 제한되어 전체 직원 조회 조건과 다르다.\n- 2번: 영업 부서 평균 급여보다 큰 모든 직원을 조회한다.\n- 3번: 평균과 같은 급여를 찾는 조건이다.\n- 4번: OR 조건으로 불필요한 영업 부서 직원까지 포함될 수 있다.\n\n**보충 개념**\n서브쿼리는 한 질의의 결과를 다른 질의의 조건으로 사용할 때 활용된다.',
   '서브쿼리', 3, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '시스템 카탈로그에 대한 설명으로 옳지 않은 것은?\n\n① 데이터베이스 객체 정의와 메타데이터를 유지 관리한다.\n② DBMS가 스스로 생성하고 유지한다.\n③ DML로 내용 조회가 가능하며 사용자가 직접 변경할 수 있다.\n④ 데이터 디렉터리에 저장된 정보를 통해 접근할 수 있다.', 'MCQ', 3, '정답: 3. 시스템 카탈로그는 조회는 가능하지만 사용자가 직접 변경할 수 없고 DBMS가 관리한다.\n\n**오답 풀이**\n- 1번: 시스템 카탈로그는 메타데이터를 저장한다.\n- 2번: DBMS가 자동으로 생성하고 유지한다.\n- 3번: 사용자가 직접 변경할 수 있다는 설명이 틀렸다.\n- 4번: 데이터 디렉터리와 관련된 메타정보를 포함한다.\n\n**보충 개념**\n시스템 카탈로그는 테이블, 뷰, 인덱스, 사용자 권한 등 DB 객체 정보를 저장한다.',
   '시스템 카탈로그', 2, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '데이터 무결성(Data Integrity)에 대한 설명으로 옳지 않은 것은?\n\n① 데이터의 정확성과 일관성을 유지하는 것을 목적으로 한다.\n② 데이터 변경 시 여러 제한을 두어 무결성을 보존한다.\n③ 개체, 참조, 사용자 정의 무결성 등이 있다.\n④ 성능 향상과 유연성 확보가 주목적이다.', 'MCQ', 4, '정답: 4. 데이터 무결성의 주목적은 성능 향상이 아니라 데이터의 정확성과 일관성 유지이다.\n\n**오답 풀이**\n- 1번: 무결성의 핵심 목적이다.\n- 2번: 제약조건을 통해 무결성을 보존한다.\n- 3번: 개체, 참조, 도메인, 사용자 정의 무결성 등이 있다.\n- 4번: 성능 향상과 유연성 확보는 주목적이 아니다.\n\n**보충 개념**\n무결성 제약조건은 잘못된 데이터 입력과 관계 불일치를 방지한다.',
   '데이터 무결성', 2, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'A 속성이 기본키이고 B 속성이 A 속성에 의해 결정된다면 함수 종속 관계를 올바르게 표현한 것은?\n\n① A → B\n② B → A\n③ A ← B\n④ A ↔ B', 'MCQ', 1, '정답: 1. A가 B를 결정하므로 A → B로 표현한다.\n\n**오답 풀이**\n- 1번: A가 결정자, B가 종속자이므로 맞다.\n- 2번: B가 A를 결정한다는 뜻이므로 반대이다.\n- 3번: A ← B는 B → A와 같은 의미이다.\n- 4번: 상호 결정 관계를 뜻하므로 문제 조건과 다르다.\n\n**보충 개념**\nX → Y는 X 값이 정해지면 Y 값도 하나로 정해진다는 의미이다.',
   '함수 종속', 1, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'SQL에서 HAVING 절을 사용하기 위해 선행되어야 하는 절은?\n\n① WHERE\n② GROUP BY\n③ ORDER BY\n④ JOIN', 'MCQ', 2, '정답: 2. HAVING은 그룹화된 결과에 조건을 적용하므로 GROUP BY와 함께 사용된다.\n\n**오답 풀이**\n- 1번: WHERE는 그룹화 전 행 조건이다.\n- 2번: GROUP BY가 HAVING의 전제가 된다.\n- 3번: ORDER BY는 정렬 절이다.\n- 4번: JOIN은 테이블 결합 절이다.\n\n**보충 개념**\nWHERE는 행 필터링, HAVING은 그룹 필터링에 사용된다.',
   'GROUP BY', 1, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'CREATE TABLE 문에 포함되지 않는 키워드는?\n\n① NOT NULL\n② PRIMARY KEY\n③ FOREIGN KEY\n④ ALTER', 'MCQ', 4, '정답: 4. ALTER는 이미 생성된 테이블의 구조를 변경하는 명령이며 CREATE TABLE 내부 키워드가 아니다.\n\n**오답 풀이**\n- 1번: NOT NULL은 컬럼 제약조건이다.\n- 2번: PRIMARY KEY는 기본키 제약조건이다.\n- 3번: FOREIGN KEY는 외래키 제약조건이다.\n- 4번: ALTER는 별도의 DDL 명령이다.\n\n**보충 개념**\nCREATE TABLE에서는 컬럼 정의와 제약조건을 함께 지정할 수 있다.',
   'CREATE TABLE', 1, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '참조되는 데이터가 갱신되거나 삭제될 때 관련 튜플도 함께 처리하도록 하는 참조 무결성 옵션은?\n\n① RESTRICT\n② NO ACTION\n③ CASCADE\n④ SET NULL', 'MCQ', 3, '정답: 3. CASCADE는 참조 대상 데이터 변경이나 삭제가 참조하는 데이터에도 연쇄적으로 반영되도록 한다.\n\n**오답 풀이**\n- 1번: RESTRICT는 참조 중인 경우 삭제나 변경을 제한한다.\n- 2번: NO ACTION은 즉시 특별 조치를 하지 않는 옵션이다.\n- 3번: CASCADE는 연쇄 변경·삭제를 수행한다.\n- 4번: SET NULL은 외래키 값을 NULL로 설정한다.\n\n**보충 개념**\n참조 무결성 옵션은 부모 데이터 변경 시 자식 데이터 처리 방식을 결정한다.',
   '참조 무결성', 2, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'Fiber Channel과 같은 고속 네트워크 기술을 사용해 대용량 데이터베이스와 고성능 컴퓨팅 환경에서 여러 저장장치를 통합 관리하는 스토리지 유형은?\n\n① NAS\n② SAN\n③ DAS\n④ KAS', 'MCQ', 2, '정답: 2. SAN은 전용 고속 네트워크를 통해 서버와 스토리지를 연결하는 방식이다.\n\n**오답 풀이**\n- 1번: NAS는 네트워크 기반 파일 저장소이다.\n- 2번: SAN은 Fiber Channel 등 고속 네트워크를 사용한다.\n- 3번: DAS는 서버에 저장장치를 직접 연결한다.\n- 4번: KAS는 대표 스토리지 유형이 아니다.\n\n**보충 개념**\nSAN은 대규모 데이터베이스와 고성능 저장장치 환경에서 자주 사용된다.',
   'SAN', 2, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '관계형 데이터베이스에서 두 릴레이션에 공통으로 존재하는 동일한 튜플만 추출하는 집합 연산자는?\n\n① UNION\n② MINUS\n③ INTERSECT\n④ JOIN', 'MCQ', 3, '정답: 3. INTERSECT는 두 릴레이션에 공통으로 존재하는 튜플만 반환한다.\n\n**오답 풀이**\n- 1번: UNION은 합집합이다.\n- 2번: MINUS는 차집합이다.\n- 3번: INTERSECT는 교집합이다.\n- 4번: JOIN은 관련 속성을 기준으로 튜플을 결합한다.\n\n**보충 개념**\n집합 연산에는 UNION, INTERSECT, MINUS 등이 있다.',
   'INTERSECT', 1, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래 SQL의 올바른 해석은?\n\n```sql\nSELECT 도서명, 저자\nFROM 도서\nWHERE 판매량 BETWEEN 200 AND 400\nORDER BY 판매량 DESC;\n```\n\n① 판매량이 200 이상 400 미만인 도서를 오름차순으로 조회한다.\n② 판매량이 200 이상 400 이하인 도서를 판매량 내림차순으로 조회한다.\n③ 판매량이 200 초과 400 미만인 도서를 내림차순으로 조회한다.\n④ 판매량이 200 초과 400 미만인 도서를 오름차순으로 조회한다.', 'MCQ', 2, '정답: 2. BETWEEN 200 AND 400은 200 이상 400 이하이고, DESC는 내림차순 정렬이다.\n\n**오답 풀이**\n- 1번: 400 미만이 아니라 400 이하이며 DESC는 내림차순이다.\n- 2번: 조건과 정렬 방향이 모두 맞다.\n- 3번: BETWEEN은 초과·미만이 아니다.\n- 4번: 조건과 정렬 방향이 모두 틀렸다.\n\n**보충 개념**\nSQL의 BETWEEN은 양 끝값을 포함한다.',
   'SQL 조회', 2, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '해시 함수의 종류에 해당하지 않는 것은?\n\n① 제산법\n② 폴딩법\n③ 난수 변환법\n④ 숫자 분석법', 'MCQ', 3, '정답: 3. 난수 변환법은 일반적인 해시 함수 분류 명칭으로 보기 어렵다.\n\n**오답 풀이**\n- 1번: 제산법은 키를 테이블 크기로 나눈 나머지를 이용한다.\n- 2번: 폴딩법은 키를 여러 부분으로 나누어 결합한다.\n- 3번: 난수 변환법은 대표 분류가 아니다.\n- 4번: 숫자 분석법은 키의 특정 자릿수를 이용한다.\n\n**보충 개념**\n해시 함수에는 제산법, 제곱법, 폴딩법, 숫자 분석법 등이 있다.',
   '해시 함수', 2, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 테스트에서 오류(error)의 의미가 가장 올바른 것은?\n\n① 잘못된 코드로 인해 포함되는 완전하지 못한 부분\n② 결함의 원인이 되는 사람의 실수나 오해\n③ 완전하지 못한 부분에 의해 의도하지 않은 결과 발생\n④ 프로그램의 결함을 찾아 수정하는 작업', 'MCQ', 2, '정답: 2. 오류는 결함을 유발하는 사람의 실수나 오해를 의미한다.\n\n**오답 풀이**\n- 1번: 결함 또는 결점에 가까운 설명이다.\n- 2번: 오류의 의미로 가장 적절하다.\n- 3번: 실패(Failure)에 가까운 설명이다.\n- 4번: 디버깅에 대한 설명이다.\n\n**보충 개념**\n오류(Error), 결함(Defect/Fault), 실패(Failure)는 테스트 용어에서 구분된다.',
   '테스트 용어', 2, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C언어 연산자 우선순위가 가장 높은 것은?\n\n① 단항 연산자\n② 산술 연산자\n③ 관계 연산자\n④ 논리 연산자', 'MCQ', 1, '정답: 1. 단항 연산자는 산술, 관계, 논리 연산자보다 우선순위가 높다.\n\n**오답 풀이**\n- 1번: 단항 연산자가 가장 우선순위가 높다.\n- 2번: 산술 연산자는 단항 연산자보다 낮다.\n- 3번: 관계 연산자는 산술 연산자보다 낮다.\n- 4번: 논리 연산자는 관계 연산자보다도 낮은 편이다.\n\n**보충 개념**\nC언어에서 연산자 우선순위를 알아야 복합 수식의 계산 순서를 정확히 판단할 수 있다.',
   'C 연산자', 1, @mock_exam_id, 61, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '객체 지향 프로그래밍에서 객체 간 통신을 위해 서로 주고받는 인터페이스이자 객체들이 메서드를 수행하도록 하는 것은?\n\n① 클래스\n② 객체\n③ 메시지\n④ 메소드', 'MCQ', 3, '정답: 3. 메시지는 객체에게 작업 수행을 요청하는 통신 수단이다.\n\n**오답 풀이**\n- 1번: 클래스는 객체를 만들기 위한 설계도이다.\n- 2번: 객체는 속성과 행위를 가진 실체이다.\n- 3번: 메시지는 객체 간 상호작용 수단이다.\n- 4번: 메소드는 객체가 수행하는 행위이다.\n\n**보충 개념**\n객체지향에서 객체는 메시지를 받아 자신의 메서드를 수행한다.',
   '메시지', 1, @mock_exam_id, 62, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '클래스(Class)에 대한 설명으로 옳지 않은 것은?\n\n① 객체의 타입을 정의하고 구현하는 틀이다.\n② 유사한 성격을 가진 객체들의 공통 특성을 추상화한 타입이다.\n③ 객체의 인스턴스이며 객체의 속성과 메서드를 가지고 있다.\n④ 객체가 가지는 속성과 객체가 수행하는 메서드를 정의한다.', 'MCQ', 3, '정답: 3. 클래스는 객체의 인스턴스가 아니라 객체를 생성하기 위한 틀이다.\n\n**오답 풀이**\n- 1번: 클래스는 객체의 타입이자 구현 틀이다.\n- 2번: 클래스는 공통 특성을 추상화한 타입이다.\n- 3번: 객체의 인스턴스라는 설명은 객체에 해당한다.\n- 4번: 클래스는 속성과 메서드를 정의한다.\n\n**보충 개념**\n객체는 클래스의 인스턴스이다.',
   '클래스', 1, @mock_exam_id, 63, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '럼바우(Rumbaugh) 분석 절차에 해당하지 않는 것은?\n\n① 객체 모델링\n② 동적 모델링\n③ 기능 모델링\n④ 정적 모델링', 'MCQ', 4, '정답: 4. 럼바우 분석 절차는 객체 모델링, 동적 모델링, 기능 모델링으로 구성된다.\n\n**오답 풀이**\n- 1번: 객체 모델링은 럼바우 분석 절차이다.\n- 2번: 동적 모델링은 럼바우 분석 절차이다.\n- 3번: 기능 모델링은 럼바우 분석 절차이다.\n- 4번: 정적 모델링은 럼바우의 대표 절차 명칭이 아니다.\n\n**보충 개념**\n럼바우 분석은 객체 → 동적 → 기능 모델링 순서로 설명된다.',
   '럼바우 분석', 2, @mock_exam_id, 64, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '로크(Lock) 단위가 큰 경우에 대한 설명으로 옳은 것은?\n\n① 병행성 수준이 높아지고 오버헤드가 증가한다.\n② 로크 수가 많아져 오버헤드가 증가한다.\n③ 병행성 수준이 낮아지고 오버헤드는 감소한다.\n④ 다수 트랜잭션 동시 수행에 적합하다.', 'MCQ', 3, '정답: 3. 로크 단위가 크면 관리할 로크 수가 줄어 오버헤드는 감소하지만 병행성은 낮아진다.\n\n**오답 풀이**\n- 1번: 로크 단위가 크면 병행성은 낮아진다.\n- 2번: 로크 수는 적어지므로 오버헤드는 감소한다.\n- 3번: 병행성 저하와 오버헤드 감소가 맞다.\n- 4번: 다수 트랜잭션 동시 수행에는 작은 로크 단위가 유리하다.\n\n**보충 개념**\n로크 단위가 작으면 병행성은 높지만 로크 관리 오버헤드가 증가한다.',
   '로킹 단위', 2, @mock_exam_id, 65, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '생성 패턴에 해당하지 않는 것은?\n\n① Factory Method\n② Abstract Factory\n③ Builder\n④ Decorator', 'MCQ', 4, '정답: 4. Decorator는 객체에 기능을 동적으로 추가하는 구조 패턴이다.\n\n**오답 풀이**\n- 1번: Factory Method는 생성 패턴이다.\n- 2번: Abstract Factory는 생성 패턴이다.\n- 3번: Builder는 생성 패턴이다.\n- 4번: Decorator는 구조 패턴이다.\n\n**보충 개념**\nGoF 디자인 패턴은 생성, 구조, 행위 패턴으로 분류된다.',
   '디자인 패턴', 1, @mock_exam_id, 66, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '가상기억장치 관리 기법 설명의 올바른 조합은?\n\n**<보기>**\nㄱ: 프로그램/메모리를 동일한 크기의 페이지와 프레임으로 나누어 적재하는 기법\nㄴ: 프로그램/메모리를 다양한 크기의 논리적 세그먼트로 나누어 적재하는 기법\n\n① ㄱ: 페이징, ㄴ: 세그먼테이션\n② ㄱ: 세그먼테이션, ㄴ: 페이징\n③ ㄱ: 오버레이, ㄴ: 스와핑\n④ ㄱ: 스와핑, ㄴ: 오버레이', 'MCQ', 1, '정답: 1. 고정 크기 단위는 페이징, 논리적 가변 크기 단위는 세그먼테이션이다.\n\n**오답 풀이**\n- 1번: 올바른 조합이다.\n- 2번: 두 개념이 반대로 연결되었다.\n- 3번: 오버레이와 스와핑은 설명과 맞지 않는다.\n- 4번: 스와핑과 오버레이는 설명과 맞지 않는다.\n\n**보충 개념**\n페이징은 외부 단편화를 줄이고, 세그먼테이션은 논리 단위 보호와 공유에 유리하다.',
   '가상기억장치', 2, @mock_exam_id, 67, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '객체지향 설계 원칙에 대한 설명으로 옳지 않은 것은?\n\n① 하나의 클래스는 제공하는 모든 기능이 하나의 목적만 향하도록 설계해야 한다.\n② 클래스는 확장에는 열려 있고 변경에는 닫혀 있어야 한다.\n③ 하위 클래스는 상위 클래스의 기능을 호환할 수 있어야 한다.\n④ 하나의 거대한 인터페이스보다 다수의 구체적인 인터페이스를 구성해야 한다.', 'MCQ', 1, '정답: 1. 제시된 설명은 단일 책임 원칙과 유사하지만 ‘제공하는 모든 기능’이라는 표현이 과도하여 객체지향 설계 원칙 설명으로 가장 부적절하다.\n\n**오답 풀이**\n- 1번: 단일 책임 원칙을 부정확하게 표현했다.\n- 2번: 개방-폐쇄 원칙에 해당한다.\n- 3번: 리스코프 치환 원칙에 해당한다.\n- 4번: 인터페이스 분리 원칙에 해당한다.\n\n**보충 개념**\nSOLID 원칙은 객체지향 설계에서 변경에 강한 구조를 만들기 위한 대표 원칙이다.',
   '객체지향 설계 원칙', 3, @mock_exam_id, 68, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'UNIX/Linux 시스템에서 파일이나 디렉터리의 접근 권한을 변경하는 데 사용되는 명령어는?\n\n① cp\n② ls\n③ chmod\n④ mv', 'MCQ', 3, '정답: 3. chmod는 파일이나 디렉터리의 접근 권한을 변경하는 명령어이다.\n\n**오답 풀이**\n- 1번: cp는 파일 복사 명령어이다.\n- 2번: ls는 파일 목록 출력 명령어이다.\n- 3번: chmod는 권한 변경 명령어이다.\n- 4번: mv는 파일 이동 또는 이름 변경 명령어이다.\n\n**보충 개념**\nchmod는 읽기, 쓰기, 실행 권한을 숫자나 기호 방식으로 변경할 수 있다.',
   'Linux 명령어', 1, @mock_exam_id, 69, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'UNIX의 구성에 대한 설명으로 가장 거리가 먼 것은?\n\n① 커널은 하드웨어와 시스템 관리 역할을 수행한다.\n② 쉘은 프로세스와 메모리를 관리하는 기능을 제공한다.\n③ 유틸리티는 문서 편집, 언어 번역 등의 기능을 제공한다.\n④ C언어 기반의 계층적 파일 시스템을 제공한다.', 'MCQ', 2, '정답: 2. 프로세스와 메모리 관리는 커널의 역할이며 쉘은 명령어 해석기이다.\n\n**오답 풀이**\n- 1번: 커널은 하드웨어와 자원을 관리한다.\n- 2번: 쉘이 프로세스와 메모리를 직접 관리한다는 설명은 틀렸다.\n- 3번: 유틸리티는 사용자 편의 기능을 제공한다.\n- 4번: UNIX는 C언어 기반이며 계층적 파일 시스템을 가진다.\n\n**보충 개념**\nUNIX는 커널, 쉘, 유틸리티로 구성된다.',
   'UNIX 구성', 1, @mock_exam_id, 70, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 HRN 스케줄링에서 가장 먼저 수행될 프로세스는?\n\n| 프로세스 | 실행시간 | 대기시간 |\n|---|---:|---:|\n| A | 15 | 18 |\n| B | 12 | 24 |\n| C | 25 | 20 |\n| D | 4 | 10 |\n\n① A\n② B\n③ C\n④ D', 'MCQ', 4, '정답: 4. HRN 우선순위는 (대기시간+실행시간)/실행시간이며 D가 가장 크다.\n\n**오답 풀이**\n- 1번: A=(18+15)/15=2.2이다.\n- 2번: B=(24+12)/12=3이다.\n- 3번: C=(20+25)/25=1.8이다.\n- 4번: D=(10+4)/4=3.5로 가장 높다.\n\n**보충 개념**\nHRN은 긴 작업의 기아 현상을 완화하기 위해 대기시간과 실행시간을 함께 고려한다.',
   'HRN', 2, @mock_exam_id, 71, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 출력 결과는?\n\n```c\n#include <stdio.h>\nint main() {\n    int a, b, c;\n    a = 5 > 0 && 10 > 0;\n    b = 3 > 5 || 7 > 5;\n    c = 10 >> 3;\n    printf("%d %d %d", a, b, c);\n    return 0;\n}\n```\n\n① 0 1 1\n② 1 1 1\n③ 1 0 0\n④ 0 0 1', 'MCQ', 2, '정답: 2. 첫 번째 논리식은 참, 두 번째 논리식도 참이고, 10을 오른쪽으로 3비트 이동하면 1이다.\n\n**오답 풀이**\n- 1번: 첫 번째 조건식은 참이므로 0이 아니다.\n- 2번: `1 1 1`이 맞다.\n- 3번: 두 번째 조건식은 참이고 비트 이동 결과도 1이다.\n- 4번: 첫 번째와 두 번째 조건식 결과가 틀렸다.\n\n**보충 개념**\nC언어에서 참은 1, 거짓은 0으로 출력될 수 있다.',
   'C 연산자', 2, @mock_exam_id, 72, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 출력 결과는?\n\n```c\n#include <stdio.h>\nint main() {\n    int sum = 0;\n    int i;\n    for (i = 1; i <= 10; i += 2) {\n        sum += i;\n    }\n    printf("%d", sum);\n    return 0;\n}\n```\n\n① 25\n② 55\n③ 50\n④ 30', 'MCQ', 1, '정답: 1. i는 1, 3, 5, 7, 9로 증가하므로 합은 25이다.\n\n**오답 풀이**\n- 1번: 1+3+5+7+9=25이다.\n- 2번: 1부터 10까지 전체 합에 가깝다.\n- 3번: 반복 조건과 증가식 계산이 틀렸다.\n- 4번: 홀수 합이 아니다.\n\n**보충 개념**\nfor문의 초기식, 조건식, 증감식을 순서대로 추적해야 한다.',
   'C 반복문', 1, @mock_exam_id, 73, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 출력 결과는?\n\n```c\n#include <stdio.h>\nint main() {\n    int a = 4;\n    int *p = &a;\n    printf("%d", &a + *p - p + a);\n    return 0;\n}\n```\n\n① 0\n② 4\n③ 8\n④ 오류', 'MCQ', 3, '정답: 3. `&a`와 `p`는 같은 주소이고, `(&a + 4) - p`는 4가 되며 여기에 a의 값 4를 더해 8이 된다.\n\n**오답 풀이**\n- 1번: 포인터 차이와 a 값을 모두 반영하지 않았다.\n- 2번: 포인터 차이만 고려한 값이다.\n- 3번: 계산 결과는 8이다.\n- 4번: 동일한 배열 객체가 아닌 포인터 산술은 엄밀히는 주의가 필요하지만 시험 문맥에서는 계산식으로 처리된다.\n\n**보충 개념**\n포인터 연산 문제는 주소값 자체보다 같은 타입 포인터 간 차이를 기준으로 해석한다.',
   'C 포인터', 4, @mock_exam_id, 74, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Java 코드의 출력 결과는?\n\n```java\npublic class Main {\n    static void div(int a, int b) {\n        try {\n            System.out.print(a/b);\n        } catch(ArithmeticException e) {\n            System.out.print("err");\n        } finally {\n            System.out.print("Done");\n        }\n    }\n    public static void main(String[] args) {\n        div(5, 5);\n    }\n}\n```\n\n① Done\n② 1Done\n③ err\n④ 1', 'MCQ', 2, '정답: 2. 5/5는 1이므로 예외가 발생하지 않고, finally 블록은 항상 실행되어 Done이 이어서 출력된다.\n\n**오답 풀이**\n- 1번: try 블록의 출력 1이 빠졌다.\n- 2번: 1과 Done이 이어서 출력되어 맞다.\n- 3번: 0으로 나누지 않았으므로 예외가 발생하지 않는다.\n- 4번: finally 블록 출력이 빠졌다.\n\n**보충 개념**\nfinally 블록은 예외 발생 여부와 관계없이 실행된다.',
   'Java 예외 처리', 2, @mock_exam_id, 75, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'C언어에서 for문이 무한 반복되도록 입력한 for문에 해당하지 않는 것은?\n\n① for(;;)\n② for(int i = 0; ; i++)\n③ for(int i = 0; i < 10;)\n④ for(int i = 0; i < 10; i++)', 'MCQ', 4, '정답: 4. `for(int i = 0; i < 10; i++)`는 i가 증가하여 10이 되면 종료된다.\n\n**오답 풀이**\n- 1번: 조건식이 없으므로 무한 반복이다.\n- 2번: 조건식이 비어 있어 무한 반복이다.\n- 3번: i가 증가하지 않으므로 조건이 계속 참이면 무한 반복된다.\n- 4번: i가 증가하여 반복이 종료된다.\n\n**보충 개념**\nfor문에서 조건식이 생략되면 참으로 간주된다.',
   'C 반복문', 2, @mock_exam_id, 76, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Java 코드의 출력 결과는?\n\n```java\npublic class Main {\n    public static int[] ma() {\n        int[] arr = new int[4];\n        for (int i = 0; i < arr.length; i++) {\n            arr[i] = i;\n        }\n        return arr;\n    }\n    public static void main(String[] args) {\n        int[] a = ma();\n        for (int i = 0; i < a.length; i++) {\n            System.out.print(a[i]);\n        }\n    }\n}\n```\n\n① 0000\n② 0123\n③ 1234\n④ 3333', 'MCQ', 2, '정답: 2. 배열 arr의 각 원소에 인덱스 값 0, 1, 2, 3이 저장되고 순서대로 출력된다.\n\n**오답 풀이**\n- 1번: 배열 기본값만 출력한 경우이다.\n- 2번: 0, 1, 2, 3이 출력되어 맞다.\n- 3번: 배열은 0부터 채워진다.\n- 4번: 모든 원소가 3으로 저장되지 않는다.\n\n**보충 개념**\nJava 배열 인덱스는 0부터 시작한다.',
   'Java 배열', 1, @mock_exam_id, 77, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중 `a * 2`와 동일한 계산식은?\n\n① a >> 2\n② a << 2\n③ a + 4\n④ a / 2', 'MCQ', 3, '정답: 3. 보기 중 `a * 2`와 항상 같아지는 조건은 문제의 전제상 a가 4일 때 `a + 4`이다.\n\n**오답 풀이**\n- 1번: `a >> 2`는 오른쪽 2비트 이동으로 나눗셈에 가깝다.\n- 2번: `a << 2`는 4배와 같다.\n- 3번: 제시된 문맥에서 a=4이면 a*2와 a+4가 모두 8이다.\n- 4번: `a / 2`는 2로 나누는 연산이다.\n\n**보충 개념**\n비트 시프트 연산은 2의 거듭제곱 곱셈 또는 나눗셈과 관련된다.',
   '연산식', 2, @mock_exam_id, 78, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Python 코드의 빈칸에 해당하는 코드는?\n\n```python\nx = 20\nif x == 10:\n    print(10)\n[빈칸] x == 20:\n    print(20)\nelse:\n    print(''other'')\n```\n\n① elseif\n② else if\n③ elif\n④ elif:', 'MCQ', 3, '정답: 3. Python에서 여러 조건을 이어서 검사할 때는 `elif 조건:` 형식을 사용하며, 빈칸에는 `elif`가 들어간다.\n\n**오답 풀이**\n- 1번: Python 키워드가 아니다.\n- 2번: Python은 `else if`를 사용하지 않는다.\n- 3번: `elif`가 올바른 키워드이다.\n- 4번: 빈칸 뒤에 조건과 콜론이 이어지므로 `elif:`는 부적절하다.\n\n**보충 개념**\nPython 조건문은 `if`, `elif`, `else` 구조를 사용한다.',
   'Python 조건문', 1, @mock_exam_id, 79, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '실수 데이터 3.654를 short 타입 변수에 할당하면 문제가 생기는 이유로 가장 적절한 것은?\n\n① 문자형 데이터를 저장하는 데 사용되기 때문이다.\n② 실수형 데이터를 저장할 수 없어 소수점 이하가 손실되기 때문이다.\n③ 메모리 공간이 너무 커서 저장하기 때문이다.\n④ short 타입과 실수형 데이터 간에는 연산자 우선순위가 동일하기 때문이다.', 'MCQ', 2, '정답: 2. short는 정수형이므로 실수값을 그대로 저장할 수 없다.\n\n**오답 풀이**\n- 1번: short는 문자형이 아니라 정수형이다.\n- 2번: 실수형 데이터를 저장할 수 없다는 점이 핵심이다.\n- 3번: 메모리 공간이 너무 커서 문제가 되는 것은 아니다.\n- 4번: 연산자 우선순위와 관련 없다.\n\n**보충 개념**\n정수형 변수에는 소수부가 있는 실수 데이터를 직접 저장할 수 없다.',
   '자료형', 2, @mock_exam_id, 80, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'TCP(Transmission Control Protocol)에 대한 설명으로 옳지 않은 것은?\n\n① 3-way 핸드셰이킹으로 연결 설정 시 지연 시간이 발생한다.\n② 신뢰성 있는 연결형 전송을 보장한다.\n③ 모든 데이터가 사전에 논리적 연결을 설정하여 데이터그램 단위로 교환된다.\n④ 체크섬, 흐름 제어 등 신뢰성 있는 전송 기능을 제공한다.', 'MCQ', 3, '정답: 3. TCP는 연결형 프로토콜이며 세그먼트 단위 전송을 수행한다. 데이터그램 중심 설명은 UDP/IP와 더 가깝다.\n\n**오답 풀이**\n- 1번: TCP는 연결 설정 과정 때문에 지연이 발생할 수 있다.\n- 2번: TCP는 신뢰성 있는 연결형 전송을 제공한다.\n- 3번: 데이터그램 단위 교환이라는 설명이 부적절하다.\n- 4번: 체크섬, 흐름 제어, 재전송 등을 제공한다.\n\n**보충 개념**\nTCP는 연결형, 신뢰성, 흐름 제어, 혼잡 제어를 제공하는 전송 계층 프로토콜이다.',
   'TCP', 2, @mock_exam_id, 81, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '하둡(Hadoop)에 대한 설명으로 옳은 것은?\n\n① 구글에서 개발한 오픈 소스 프레임워크이다.\n② 대용량 데이터를 효율적으로 처리할 수 있는 분산 컴퓨팅 플랫폼이다.\n③ 웹사이트를 빠르게 만드는 웹 기반 공격이다.\n④ 전기가 없는 상태에서 작동하는 저장장치이다.', 'MCQ', 2, '정답: 2. Hadoop은 대용량 데이터를 분산 저장하고 처리하기 위한 오픈소스 프레임워크이다.\n\n**오답 풀이**\n- 1번: Hadoop은 Apache 오픈소스 프로젝트이다.\n- 2번: 대용량 데이터 분산 처리 플랫폼이라는 설명이 맞다.\n- 3번: 웹 공격 기법이 아니다.\n- 4번: 저장장치 하드웨어 설명이 아니다.\n\n**보충 개념**\nHadoop은 HDFS와 MapReduce 등을 기반으로 대용량 데이터를 처리한다.',
   'Hadoop', 1, @mock_exam_id, 82, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '정보보안의 3요소(CIA)에 해당하지 않는 것은?\n\n① 기밀성\n② 무결성\n③ 가용성\n④ 인증', 'MCQ', 4, '정답: 4. 정보보안 3요소는 기밀성, 무결성, 가용성이며 인증은 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 기밀성은 CIA의 C이다.\n- 2번: 무결성은 CIA의 I이다.\n- 3번: 가용성은 CIA의 A이다.\n- 4번: 인증은 정보보안 3요소 자체는 아니다.\n\n**보충 개념**\nCIA는 Confidentiality, Integrity, Availability의 약자이다.',
   '정보보안 3요소', 1, @mock_exam_id, 83, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '암호 관련 용어와 의미가 바르게 연결되지 않은 것은?\n\n① 평문: 암호화 대상 문장\n② 암호문: 암호화 결과\n③ 암호화: 암호문을 평문으로 변환하는 과정\n④ 키: 암호화와 복호화에 필요한 매개변수', 'MCQ', 3, '정답: 3. 암호문을 평문으로 변환하는 과정은 복호화이다.\n\n**오답 풀이**\n- 1번: 평문은 암호화 전 원문이다.\n- 2번: 암호문은 암호화 결과이다.\n- 3번: 암호화가 아니라 복호화 설명이다.\n- 4번: 키는 암호화와 복호화에 사용된다.\n\n**보충 개념**\n암호화는 평문을 암호문으로 바꾸고, 복호화는 암호문을 평문으로 되돌린다.',
   '암호 용어', 1, @mock_exam_id, 84, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '하나의 메인 통신 회선에 다수의 단말기가 연결된 네트워크 구조는?\n\n① 스타 토폴로지\n② 버스 토폴로지\n③ 링 토폴로지\n④ 메시 토폴로지', 'MCQ', 2, '정답: 2. 버스 토폴로지는 하나의 공통 통신 회선에 여러 장치가 연결되는 구조이다.\n\n**오답 풀이**\n- 1번: 스타는 중앙 장치에 각 노드가 연결된다.\n- 2번: 버스는 하나의 메인 회선을 공유한다.\n- 3번: 링은 노드가 고리 형태로 연결된다.\n- 4번: 메시 토폴로지는 여러 노드가 그물망처럼 연결된다.\n\n**보충 개념**\n버스 구조는 설치가 간단하지만 메인 회선 장애 시 전체 통신에 영향이 크다.',
   '네트워크 토폴로지', 1, @mock_exam_id, 85, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'OSI 7계층의 계층별 데이터 단위(PDU)에 대한 설명으로 옳지 않은 것은?\n\n① 데이터 링크 계층: 프레임\n② 전송 계층: 세그먼트\n③ 네트워크 계층: 패킷\n④ 응용 계층: 비트', 'MCQ', 4, '정답: 4. 비트는 물리 계층의 데이터 단위이며 응용 계층의 PDU가 아니다.\n\n**오답 풀이**\n- 1번: 데이터 링크 계층의 PDU는 프레임이다.\n- 2번: 전송 계층의 PDU는 세그먼트이다.\n- 3번: 네트워크 계층의 PDU는 패킷이다.\n- 4번: 비트는 물리 계층에 해당한다.\n\n**보충 개념**\n대표 PDU는 응용 계층 데이터, 전송 계층 세그먼트, 네트워크 계층 패킷, 데이터링크 계층 프레임, 물리 계층 비트이다.',
   'OSI PDU', 1, @mock_exam_id, 86, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '링크 상태(Link-State Vector) 방식의 라우팅 프로토콜은?\n\n① RIP\n② EIGRP\n③ EGP\n④ IGRP', 'MCQ', 2, '정답: 2. 제시된 보기 중 EIGRP가 링크 상태 특성을 일부 결합한 고급 라우팅 프로토콜로 가장 가깝다.\n\n**오답 풀이**\n- 1번: RIP는 거리 벡터 라우팅 프로토콜이다.\n- 2번: EIGRP는 고급 거리 벡터 또는 하이브리드 성격으로 설명된다.\n- 3번: EGP는 외부 게이트웨이 프로토콜이다.\n- 4번: IGRP는 거리 벡터 라우팅 프로토콜이다.\n\n**보충 개념**\n일반적인 링크 상태 라우팅 프로토콜로는 OSPF와 IS-IS가 대표적이다.',
   '라우팅 프로토콜', 3, @mock_exam_id, 87, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '192.168.64.0/22 네트워크에서 FLSM 방식으로 26개 호스트가 필요한 서브넷으로 나눌 때, 5번째 네트워크에서 사용 가능한 IP 주소가 아닌 것은?\n\n① 192.168.64.130\n② 192.168.64.145\n③ 192.168.64.158\n④ 192.168.64.159', 'MCQ', 4, '정답: 4. 26개 호스트를 수용하려면 /27 서브넷이 필요하며, 192.168.64.128/27에서 192.168.64.159는 브로드캐스트 주소이다.\n\n**오답 풀이**\n- 1번: 192.168.64.130은 사용 가능한 호스트 주소이다.\n- 2번: 192.168.64.145는 사용 가능한 호스트 주소이다.\n- 3번: 192.168.64.158은 사용 가능한 호스트 주소이다.\n- 4번: 192.168.64.159는 브로드캐스트 주소이므로 사용할 수 없다.\n\n**보충 개념**\n/27은 32개 주소를 제공하며 네트워크 주소와 브로드캐스트 주소를 제외한 30개가 호스트 주소이다.',
   '서브넷팅', 4, @mock_exam_id, 88, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '가상 세계에 현실 속 사물이나 시스템을 복제하여 현실에서 발생 가능한 상황을 시뮬레이션하는 기술은?\n\n① 빅데이터\n② 인공지능\n③ 디지털 트윈\n④ 클라우드 컴퓨팅', 'MCQ', 3, '정답: 3. 디지털 트윈은 현실의 사물이나 시스템을 가상 공간에 복제하여 분석과 시뮬레이션을 수행하는 기술이다.\n\n**오답 풀이**\n- 1번: 빅데이터는 대규모 데이터 처리와 분석을 의미한다.\n- 2번: 인공지능은 지능적 판단과 학습 기술이다.\n- 3번: 디지털 트윈은 현실 시스템의 가상 복제 기술이다.\n- 4번: 클라우드 컴퓨팅은 컴퓨팅 자원을 네트워크로 제공하는 방식이다.\n\n**보충 개념**\n디지털 트윈은 제조, 도시, 의료, 에너지 분야에서 예측과 최적화에 활용된다.',
   '디지털 트윈', 1, @mock_exam_id, 89, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IoT 환경에서 저전력, 저대역폭 통신을 위해 설계된 Publish-Subscribe 기반 경량 프로토콜은?\n\n① HTTP\n② FTP\n③ MQTT\n④ SMTP', 'MCQ', 3, '정답: 3. MQTT는 발행-구독 모델 기반의 경량 메시징 프로토콜이다.\n\n**오답 풀이**\n- 1번: HTTP는 웹 통신 프로토콜이다.\n- 2번: FTP는 파일 전송 프로토콜이다.\n- 3번: MQTT는 IoT 환경에 적합한 경량 프로토콜이다.\n- 4번: SMTP는 이메일 전송 프로토콜이다.\n\n**보충 개념**\nMQTT는 브로커를 중심으로 발행자와 구독자가 메시지를 주고받는다.',
   'MQTT', 1, @mock_exam_id, 90, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'Secure OS의 주요 기능에 해당하지 않는 것은?\n\n① 식별 및 인증\n② 접근 통제\n③ 메모리 재사용 방지\n④ 성능 최적화', 'MCQ', 4, '정답: 4. Secure OS의 주요 기능은 보안 통제이며 성능 최적화는 핵심 보안 기능이 아니다.\n\n**오답 풀이**\n- 1번: 식별 및 인증은 Secure OS 기능이다.\n- 2번: 접근 통제는 Secure OS 기능이다.\n- 3번: 메모리 재사용 방지는 보안 기능에 해당한다.\n- 4번: 성능 최적화는 보안 기능으로 보기 어렵다.\n\n**보충 개념**\nSecure OS는 강제 접근 통제, 감사 추적, 객체 재사용 보호 등을 제공한다.',
   'Secure OS', 1, @mock_exam_id, 91, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '프로젝트 진행 중 새로운 인력을 투입하면 오히려 개발 일정이 지연될 수 있다는 법칙은?\n\n① 레이리의 법칙\n② 브룩스의 법칙\n③ 퍼트남의 법칙\n④ 파레토의 법칙', 'MCQ', 2, '정답: 2. 브룩스의 법칙은 지연된 소프트웨어 프로젝트에 인력을 추가하면 더 늦어진다는 법칙이다.\n\n**오답 풀이**\n- 1번: 레이리 법칙은 인력 분포와 관련된다.\n- 2번: 브룩스의 법칙이 맞다.\n- 3번: 퍼트남 모델은 비용 산정과 관련된다.\n- 4번: 파레토 법칙은 80:20 법칙으로 알려져 있다.\n\n**보충 개념**\n새 인력 투입은 교육, 의사소통, 조정 비용을 증가시켜 일정 지연을 악화할 수 있다.',
   '브룩스의 법칙', 1, @mock_exam_id, 92, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'COCOMO 모델 중 30만 라인 이상의 대규모 실시간/임베디드 시스템에 적용되는 유형은?\n\n① Organic\n② Semi-Detached\n③ Embedded\n④ Detailed', 'MCQ', 3, '정답: 3. Embedded 모드는 복잡도와 제약이 큰 대규모 시스템에 적용된다.\n\n**오답 풀이**\n- 1번: Organic은 소규모·단순 프로젝트에 적용된다.\n- 2번: Semi-Detached는 중간 규모 프로젝트에 적용된다.\n- 3번: Embedded는 대규모·복잡한 시스템에 적용된다.\n- 4번: Detailed는 COCOMO의 세부 산정 모델 수준이다.\n\n**보충 개념**\nCOCOMO는 소프트웨어 규모를 기준으로 노력과 비용을 산정하는 모델이다.',
   'COCOMO', 2, @mock_exam_id, 93, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '암호화 알고리즘 보기에서 ㄱ, ㄴ에 해당하는 것은?\n\n**<보기>**\nㄱ: 이산대수의 난해성에 기반한 공개키 암호 알고리즘\nㄴ: 큰 합성수의 소인수분해가 어렵다는 점을 이용한 알고리즘\n\n① ㄱ: RSA, ㄴ: ECC\n② ㄱ: ECC, ㄴ: RSA\n③ ㄱ: DES, ㄴ: AES\n④ ㄱ: AES, ㄴ: DES', 'MCQ', 2, '정답: 2. ECC는 타원곡선 이산대수 문제에 기반하고, RSA는 큰 수의 소인수분해 어려움에 기반한다.\n\n**오답 풀이**\n- 1번: RSA와 ECC의 근거가 반대로 연결되었다.\n- 2번: ECC와 RSA가 올바르게 연결되었다.\n- 3번: DES와 AES는 대칭키 암호이다.\n- 4번: AES와 DES는 대칭키 암호이다.\n\n**보충 개념**\n공개키 암호는 수학적으로 풀기 어려운 문제를 보안성의 기반으로 삼는다.',
   '공개키 암호', 2, @mock_exam_id, 94, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '사용자 인증 요소에 해당하지 않는 것은?\n\n① 지식 기반 인증\n② 소유 기반 인증\n③ 생체 기반 인증\n④ 역할 기반 인증', 'MCQ', 4, '정답: 4. 역할 기반은 접근 통제 모델과 관련되며 인증 요소 분류가 아니다.\n\n**오답 풀이**\n- 1번: 지식 기반 인증은 비밀번호 등 사용자가 아는 것이다.\n- 2번: 소유 기반 인증은 카드, 토큰 등 사용자가 가진 것이다.\n- 3번: 생체 기반 인증은 지문, 홍채 등 사용자 자체의 특성이다.\n- 4번: 역할 기반은 권한 관리 방식이다.\n\n**보충 개념**\n인증 요소는 Something You Know, Have, Are로 구분할 수 있다.',
   '인증 요소', 1, @mock_exam_id, 95, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IPv6에 대한 설명으로 옳지 않은 것은?\n\n① 128비트 주소 체계를 사용한다.\n② 주소는 16진수와 콜론으로 표현한다.\n③ 유니캐스트, 애니캐스트, 브로드캐스트 전송 방식을 가진다.\n④ 주소 자동 설정 기능을 제공한다.', 'MCQ', 3, '정답: 3. IPv6는 브로드캐스트를 사용하지 않고 유니캐스트, 멀티캐스트, 애니캐스트를 사용한다.\n\n**오답 풀이**\n- 1번: IPv6 주소는 128비트이다.\n- 2번: IPv6는 16진수와 콜론으로 표현한다.\n- 3번: IPv6에는 브로드캐스트가 없다.\n- 4번: IPv6는 주소 자동 설정을 지원한다.\n\n**보충 개념**\nIPv6는 IPv4 주소 고갈 문제 해결을 위해 128비트 주소 체계를 사용한다.',
   'IPv6', 1, @mock_exam_id, 96, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'DES의 블록 크기는 몇 bit인가?\n\n① 128\n② 64\n③ 112\n④ 60', 'MCQ', 2, '정답: 2. DES는 64비트 블록 크기를 사용하는 대칭키 블록 암호이다.\n\n**오답 풀이**\n- 1번: 128비트는 AES 블록 크기와 관련된다.\n- 2번: DES의 블록 크기는 64비트이다.\n- 3번: 112비트는 2-key 3DES의 유효 키 길이와 관련될 수 있다.\n- 4번: 60비트는 DES 블록 크기가 아니다.\n\n**보충 개념**\nDES는 56비트 키와 64비트 블록을 사용하는 고전적인 대칭키 암호이다.',
   'DES', 1, @mock_exam_id, 97, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '클린 코드(Clean Code)에 대한 설명으로 옳지 않은 것은?\n\n① 가독성이 높고 단순해야 한다.\n② 기능 및 설계 이해가 쉬워 개발 속도에 도움이 된다.\n③ 기능 구현을 위해 중복성을 많이 두는 것이 좋다.\n④ 중복성을 최소화하고 추상화를 적절히 적용해야 한다.', 'MCQ', 3, '정답: 3. 클린 코드는 중복을 줄이고 의도를 명확히 드러내는 코드를 지향한다.\n\n**오답 풀이**\n- 1번: 클린 코드는 읽기 쉬워야 한다.\n- 2번: 이해하기 쉬운 코드는 개발과 유지보수에 도움을 준다.\n- 3번: 중복성을 많이 두는 것은 클린 코드와 반대이다.\n- 4번: 중복 최소화와 적절한 추상화는 클린 코드 원칙에 부합한다.\n\n**보충 개념**\n클린 코드는 가독성, 단순성, 중복 제거, 명확한 책임 분리를 중시한다.',
   'Clean Code', 1, @mock_exam_id, 98, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '방화벽(Firewall)에 대한 설명으로 옳지 않은 것은?\n\n① 내부망과 외부망을 차단해 내부 네트워크를 보호한다.\n② 프로그램 내부의 바이러스나 웜을 탐지하고 치료한다.\n③ 시스템 보안 정책에 따라 접근을 제어한다.\n④ 화이트리스트와 블랙리스트 정책을 사용할 수 있다.', 'MCQ', 2, '정답: 2. 방화벽은 네트워크 접근을 제어하는 장치이며 프로그램 내부의 바이러스나 웜을 탐지·치료하는 백신이 아니다.\n\n**오답 풀이**\n- 1번: 방화벽은 내외부망 사이의 접근을 통제한다.\n- 2번: 악성코드 탐지·치료는 백신의 역할이다.\n- 3번: 보안 정책에 따라 트래픽을 허용하거나 차단한다.\n- 4번: 화이트리스트와 블랙리스트 정책을 사용할 수 있다.\n\n**보충 개념**\n방화벽은 패킷 필터링, 프록시, 상태 기반 검사 등을 통해 네트워크를 보호한다.',
   '방화벽', 1, @mock_exam_id, 99, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '비밀키(대칭키) 암호화 방식에 해당하지 않는 것은?\n\n① DES\n② RSA\n③ SEED\n④ ARIA', 'MCQ', 2, '정답: 2. RSA는 공개키 기반의 비대칭키 암호 방식이다.\n\n**오답 풀이**\n- 1번: DES는 대칭키 암호이다.\n- 2번: RSA는 비대칭키 암호이다.\n- 3번: SEED는 대칭키 암호이다.\n- 4번: ARIA는 대칭키 암호이다.\n\n**보충 개념**\n대칭키 암호는 암호화와 복호화에 같은 키를 사용하고, 공개키 암호는 공개키와 개인키를 사용한다.',
   '대칭키 암호', 1, @mock_exam_id, 100, 'NONE', NULL, NOW(6), NOW(6))
;